import{_ as o,W as c,X as l,Y as n,Z as s,$ as e,a2 as t,a0 as d,C as p}from"./framework-174e6972.js";const i={},r=d(`<h2 id="_1-前言" tabindex="-1"><a class="header-anchor" href="#_1-前言" aria-hidden="true">#</a> 1. 前言</h2><p>此文旨在汇总从建立数据库到联接查询等绝大部分<code>SQL</code>语句。<code>SQL</code>语句虽不能说很多，但稍有时间不写就容易出错。</p><p><code>SQL</code>是 <code>Structured Query Language</code> 即“结构化查询语言”的简称，它是用来管理关系型数据库的。</p><p>其包括：</p><ol><li><p>数据控制语言（<code>DCL</code>）(<code>Data Control Language</code>)【使用最少】</p><p>是用来设置或更改数据库用户或角色权限的语句，包括（<code>grant</code>,<code>deny</code>,<code>revoke</code>等）语句。在默认状态下，只有<code>sysadmin</code>,<code>dbcreator</code>,<code>db_owner</code>或<code>db_securityadmin</code>等人员才有权力执行<code>DCL</code></p></li><li><p>数据定义语言（<code>DDL</code>）(<code>Data Definition Language</code>)</p><p><code>DDL</code>允许用户定义数据，也就是创建表、删除表、修改表结构这些操作。通常，<code>DDL</code>由数据库管理员执行。</p></li><li><p>数据查询语言（<code>DQL</code>）(<code>Data Query Language</code>)【使用最多，其中的联合查询内容最重要】</p><p><code>DQL</code>允许用户查询数据，这也是通常最频繁的数据库日常操作</p></li><li><p>数据操作语言（<code>DML</code>）(<code>Data Manipulation Language</code>)</p><p><code>DML</code>为用户提供添加、删除、更新数据的能力，这些是应用程序对数据库的日常操作。</p></li></ol><h2 id="_2-语法特点" tabindex="-1"><a class="header-anchor" href="#_2-语法特点" aria-hidden="true">#</a> 2. 语法特点</h2><p>SQL语言关键字不区分大小写！！！但是，针对不同的数据库，对于表名和列名，有的数据库区分大小写，有的数据库不区分大小写。同一个数据库，有的在<code>Linux</code>上区分大小写，有的在<code>Windows</code>上不区分大小写。</p><p>所以，本教程约定：SQL关键字总是大写，以示突出，表名和列名均使用小写。</p><h2 id="_3-对数据库的操作" tabindex="-1"><a class="header-anchor" href="#_3-对数据库的操作" aria-hidden="true">#</a> 3. 对数据库的操作</h2><h3 id="_3-1-创建数据库" tabindex="-1"><a class="header-anchor" href="#_3-1-创建数据库" aria-hidden="true">#</a> 3.1. 创建数据库</h3><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">CREATE</span> <span class="token keyword">DATABASE</span> 数据库名<span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>数据库名命名规则：</p>`,12),u=d(`<p>本文以<code>SQLyog</code>软件为例，创建数据库如下：</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">CREATE</span> <span class="token keyword">DATABASE</span> test_sql<span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p><img src="https://pic.downk.cc/item/5e8585d1504f4bcb04ce88cd.jpg" alt="" loading="lazy"></p><p>此图为<code>SQLyog</code>的左侧目录栏，前三个为本地自带数据库。将<code>SQL</code>语句全部选中运行（<code>F8</code>）后，<code>F5</code>刷新目录栏，出现了我们创建的数据库。</p><h3 id="_3-2-查看数据库" tabindex="-1"><a class="header-anchor" href="#_3-2-查看数据库" aria-hidden="true">#</a> 3.2. 查看数据库</h3><p>查看当前有几个数据库可供连接。</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">SHOW</span> <span class="token keyword">DATABASES</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h3 id="_3-3-连接数据库" tabindex="-1"><a class="header-anchor" href="#_3-3-连接数据库" aria-hidden="true">#</a> 3.3. 连接数据库</h3><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">USE</span> test_sql<span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h3 id="_3-4-查看当前连接数据库" tabindex="-1"><a class="header-anchor" href="#_3-4-查看当前连接数据库" aria-hidden="true">#</a> 3.4. 查看当前连接数据库</h3><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">SELECT</span> <span class="token keyword">DATABASE</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h3 id="_3-5-删除数据库" tabindex="-1"><a class="header-anchor" href="#_3-5-删除数据库" aria-hidden="true">#</a> 3.5. 删除数据库</h3><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">DROP</span> <span class="token keyword">DATABASE</span> test_sql<span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h2 id="_4-mysql数据类型" tabindex="-1"><a class="header-anchor" href="#_4-mysql数据类型" aria-hidden="true">#</a> 4. MySQL数据类型</h2><p>接下来就开始创建表了，在创建表之前先列出几种常用的数据类型</p><h3 id="_4-1-整数数据类型" tabindex="-1"><a class="header-anchor" href="#_4-1-整数数据类型" aria-hidden="true">#</a> 4.1. 整数数据类型</h3><table><thead><tr><th><strong>名称</strong></th><th><strong>类型</strong></th><th><strong>说明</strong></th></tr></thead><tbody><tr><td><code>INT</code></td><td>整型</td><td>4字节整数类型，范围约<code>+/-21亿</code></td></tr><tr><td><code>BIGINT</code></td><td>长整型</td><td>8字节整数类型，范围约<code>+/-922亿亿</code></td></tr></tbody></table><h3 id="_4-2-浮点数据类型" tabindex="-1"><a class="header-anchor" href="#_4-2-浮点数据类型" aria-hidden="true">#</a> 4.2. 浮点数据类型</h3><table><thead><tr><th><strong>名称</strong></th><th><strong>类型</strong></th><th><strong>说明</strong></th></tr></thead><tbody><tr><td><code>FLOAT</code>或<code>REAL</code></td><td>浮点型</td><td>4字节浮点数，范围约<code>+/-1038</code>，精度7位小数</td></tr><tr><td><code>DOUBLE</code></td><td>浮点型</td><td>8字节浮点数，范围约<code>+/-10308</code>，精度15位小数</td></tr></tbody></table><blockquote><p>因为不精准，因此不能使用在货币这类严格要求准确的位置，通常我们更经常使用整数类型用来计算货币。</p></blockquote><h3 id="_4-3-高精度小数" tabindex="-1"><a class="header-anchor" href="#_4-3-高精度小数" aria-hidden="true">#</a> 4.3. 高精度小数</h3><table><thead><tr><th><strong>名称</strong></th><th><strong>类型</strong></th><th><strong>说明</strong></th></tr></thead><tbody><tr><td><code>DECIMAL(M,N)</code></td><td>高精度小数</td><td>由用户指定精度的小数，例如，<code>DECIMAL(20,10)</code>表示一共20位，其中小数10位，通常用于财务计算</td></tr></tbody></table><h3 id="_4-4-字符串数据类型" tabindex="-1"><a class="header-anchor" href="#_4-4-字符串数据类型" aria-hidden="true">#</a> 4.4. 字符串数据类型</h3><table><thead><tr><th><strong>名称</strong></th><th><strong>类型</strong></th><th><strong>说明</strong></th></tr></thead><tbody><tr><td><code>CHAR(N)</code></td><td>定长字符串</td><td>存储指定长度的字符串，例如，<code>CHAR(100)</code>总是存储100个字符的字符串</td></tr><tr><td><code>VARCHAR(N)</code></td><td>变长字符串</td><td>存储可变长度的字符串，例如，<code>VARCHAR(100)</code>可以存储0~100个字符的字符串</td></tr></tbody></table><h3 id="_4-5-布尔类型" tabindex="-1"><a class="header-anchor" href="#_4-5-布尔类型" aria-hidden="true">#</a> 4.5. 布尔类型</h3><table><thead><tr><th><strong>名称</strong></th><th><strong>类型</strong></th><th><strong>说明</strong></th></tr></thead><tbody><tr><td><code>BOOLEAN</code></td><td>布尔类型</td><td>存储True或者False</td></tr></tbody></table><h3 id="_4-6-枚举类型" tabindex="-1"><a class="header-anchor" href="#_4-6-枚举类型" aria-hidden="true">#</a> 4.6. 枚举类型</h3><table><thead><tr><th><strong>名称</strong></th><th><strong>类型</strong></th><th><strong>说明</strong></th></tr></thead><tbody><tr><td><code>ENUM</code></td><td>枚举类型</td><td>只能存指定的值，一般用于表单的多选框，如：男，女，未知，SQL可存为：1，2，0</td></tr></tbody></table><p>使用示例：</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">CREATE</span> <span class="token keyword">TABLE</span> my_table <span class="token punctuation">(</span>
  id <span class="token keyword">INT</span> <span class="token keyword">PRIMARY</span> <span class="token keyword">KEY</span><span class="token punctuation">,</span>
  <span class="token keyword">status</span> <span class="token keyword">ENUM</span><span class="token punctuation">(</span><span class="token string">&#39;active&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;inactive&#39;</span><span class="token punctuation">)</span> <span class="token operator">NOT</span> <span class="token boolean">NULL</span> <span class="token keyword">DEFAULT</span> <span class="token string">&#39;active&#39;</span>
<span class="token punctuation">)</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><div class="hint-container info"><p class="hint-container-title">说明</p><p><code>status</code> 字段只能取 <code>&#39;active&#39;</code> 或 <code>&#39;inactive&#39;</code> 两个选项值。默认值被设置为 <code>&#39;active&#39;</code>。</p></div><h3 id="_4-7-日期数据类型" tabindex="-1"><a class="header-anchor" href="#_4-7-日期数据类型" aria-hidden="true">#</a> 4.7. 日期数据类型</h3><table><thead><tr><th><strong>名称</strong></th><th><strong>类型</strong></th><th><strong>说明</strong></th></tr></thead><tbody><tr><td><code>DATE</code></td><td>日期类型</td><td>存储日期，例如，2018-06-22</td></tr><tr><td><code>TIME</code></td><td>时间类型</td><td>存储时间，例如，12:20:59</td></tr><tr><td><code>DATETIME</code></td><td>日期和时间类型</td><td>存储日期+时间，例如，2018-06-22 12:20:59</td></tr></tbody></table><h2 id="_5-对表的操作-ddl" tabindex="-1"><a class="header-anchor" href="#_5-对表的操作-ddl" aria-hidden="true">#</a> 5. 对表的操作(<code>DDL</code>)</h2><p>也就是前面说的 数据定义语言（<code>DDL</code>）(<code>Data Definition Language</code>)。</p><p>数据库中对表的操作有：</p><ul><li>创建表；</li><li>查看表的数量；</li><li>查看表的结构;</li><li>删除表；</li><li>复制表； <ul><li>复制表的结构及内容</li><li>只复制表的结构</li></ul></li><li>修改表； <ul><li>添加列</li><li>更改列</li><li>删除列</li></ul></li></ul><h3 id="_5-1-创建表" tabindex="-1"><a class="header-anchor" href="#_5-1-创建表" aria-hidden="true">#</a> 5.1. 创建表</h3><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">CREATE</span> <span class="token keyword">TABLE</span> <span class="token operator">&lt;</span> 表名 <span class="token operator">&gt;</span> <span class="token punctuation">(</span><span class="token operator">&lt;</span> 列名 <span class="token operator">&gt;</span> <span class="token operator">&lt;</span> 列的数据类型 <span class="token operator">&gt;</span> <span class="token punctuation">[</span><span class="token operator">&lt;</span>列的约束<span class="token operator">&gt;</span><span class="token punctuation">]</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>如：</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">CREATE</span> <span class="token keyword">TABLE</span> t_student<span class="token punctuation">(</span>
  <span class="token comment"># utf8字符集下中文一个字占三个字符</span>
  student_name <span class="token keyword">VARCHAR</span><span class="token punctuation">(</span><span class="token number">20</span><span class="token punctuation">)</span><span class="token punctuation">,</span>
  student_birthday <span class="token keyword">DATETIME</span><span class="token punctuation">,</span>
  student_phone <span class="token keyword">INT</span><span class="token punctuation">,</span>
  student_score <span class="token keyword">FLOAT</span>
<span class="token punctuation">)</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>上表中我们创建了一张学生表，并定义了姓名、生日、电话、得分四列，列名后加上数据类型。其中要注意的是<code>VARCHAR</code>需要在括号内设置字符串的最大长度。</p><p>刷新之后就可以看到我们创建的数据库中多了一张表：</p><p><img src="https://pic.downk.cc/item/5e858623504f4bcb04ceca12.jpg" alt="" loading="lazy"></p><p>选择打开表可以直观的看到内容：</p><p><img src="https://pic.downk.cc/item/5e858643504f4bcb04cee0cf.jpg" alt="" loading="lazy"></p><p>之后我们可以通过SQL语句也可以通过手动为表添加内容。</p><h3 id="_5-2-查看表的数量" tabindex="-1"><a class="header-anchor" href="#_5-2-查看表的数量" aria-hidden="true">#</a> 5.2. 查看表的数量</h3><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">SHOW</span> <span class="token keyword">TABLES</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h3 id="_5-3-查看表的结构" tabindex="-1"><a class="header-anchor" href="#_5-3-查看表的结构" aria-hidden="true">#</a> 5.3. 查看表的结构</h3><p>如果你想要知道一个表的结构，可以使用<code>DESCRIBE</code>命令；它显示表中每个列的信息：</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">DESCRIBE</span> t_student<span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h3 id="_5-4-删除表" tabindex="-1"><a class="header-anchor" href="#_5-4-删除表" aria-hidden="true">#</a> 5.4. 删除表</h3><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">DROP</span> <span class="token keyword">TABLE</span> t_student<span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h3 id="_5-5-复制表" tabindex="-1"><a class="header-anchor" href="#_5-5-复制表" aria-hidden="true">#</a> 5.5. 复制表</h3><h4 id="_5-5-1-同时复制表的结构和内容" tabindex="-1"><a class="header-anchor" href="#_5-5-1-同时复制表的结构和内容" aria-hidden="true">#</a> 5.5.1. 同时复制表的结构和内容</h4><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">CREATE</span> <span class="token keyword">TABLE</span> copy_student
<span class="token keyword">SELECT</span>
  <span class="token operator">*</span>
<span class="token keyword">FROM</span> t_student<span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>如此我们便复制了一张名为<code>copy_student</code>的表，它包括<code>t_student</code>表中的内容与结构。</p><div class="hint-container warning"><p class="hint-container-title">注意</p><p>复制表的同时表的约束并不能复制过来。</p></div><h4 id="_5-5-2-只复制表结构而不复制表内容" tabindex="-1"><a class="header-anchor" href="#_5-5-2-只复制表结构而不复制表内容" aria-hidden="true">#</a> 5.5.2. 只复制表结构而不复制表内容</h4><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">CREATE</span> <span class="token keyword">TABLE</span> copy_student
<span class="token keyword">SELECT</span>
  <span class="token operator">*</span>
<span class="token keyword">FROM</span> t_student
<span class="token keyword">WHERE</span>
  <span class="token number">1</span> <span class="token operator">=</span> <span class="token number">0</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>只需在<code>WHERE</code>条件中加入一个永不为真的值即可。</p><h3 id="_5-6-修改表" tabindex="-1"><a class="header-anchor" href="#_5-6-修改表" aria-hidden="true">#</a> 5.6. 修改表</h3><h4 id="_5-6-1-添加新列" tabindex="-1"><a class="header-anchor" href="#_5-6-1-添加新列" aria-hidden="true">#</a> 5.6.1. 添加新列</h4><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">ALTER</span> <span class="token keyword">TABLE</span> t_student
<span class="token keyword">ADD</span>
  student_address <span class="token keyword">VARCHAR</span><span class="token punctuation">(</span><span class="token number">50</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><img src="https://pic.downk.cc/item/5e858643504f4bcb04cee0cf.jpg" alt="" loading="lazy"></p><h4 id="_5-6-2-更改列" tabindex="-1"><a class="header-anchor" href="#_5-6-2-更改列" aria-hidden="true">#</a> 5.6.2. 更改列</h4><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">ALTER</span> <span class="token keyword">TABLE</span> t_student
CHANGE
  student_birthday student_age <span class="token keyword">INT</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>这里我们把学生生日列（<code>student_birthday</code>）改为学生年龄列（<code>student_age</code>），<code>CHANGE</code>后第一个为旧列名，第二个为新列名。</p><p><img src="https://pic.downk.cc/item/5e85867c504f4bcb04cf0e43.jpg" alt="" loading="lazy"></p><h4 id="_5-6-3-删除列" tabindex="-1"><a class="header-anchor" href="#_5-6-3-删除列" aria-hidden="true">#</a> 5.6.3. 删除列</h4><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">ALTER</span> <span class="token keyword">TABLE</span> t_student
<span class="token keyword">DROP</span> <span class="token keyword">COLUMN</span>
  student_score<span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><img src="https://pic.downk.cc/item/5e8586ed504f4bcb04cf65cf.jpg" alt="" loading="lazy"></p><h2 id="_6-数据库完整性" tabindex="-1"><a class="header-anchor" href="#_6-数据库完整性" aria-hidden="true">#</a> 6. 数据库完整性</h2><p>保证数据库的完整性是为了防止垃圾数据的产生，以免影响数据库的执行效率。这里简要说一些，因为毕竟不是理论类的文章，这里主要是整理汇总<code>SQL</code>语句。</p><p><strong>分类：</strong></p><ol><li><p>实体完整性（主键约束，唯一约束） 保证一行数据是有效的</p></li><li><p>域完整性（非空约束，默认约束） 保证一列数据是有效的</p></li><li><p>引用完整性（外键约束） 保证引用的编号是有效的</p></li><li><p>用户自定义完整性 保证自定义规则</p></li></ol><h3 id="_6-1-实体完整性-主键约束" tabindex="-1"><a class="header-anchor" href="#_6-1-实体完整性-主键约束" aria-hidden="true">#</a> 6.1. 实体完整性--主键约束</h3><p>关键字：<code>PRIMARY KEY</code></p><p>主键列不能为空也不能重复，通常加在表的id列中。</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">CREATE</span> <span class="token keyword">TABLE</span> t_student<span class="token punctuation">(</span>
  student_id <span class="token keyword">INT</span> <span class="token keyword">PRIMARY</span> <span class="token keyword">KEY</span><span class="token punctuation">,</span>
  student_name <span class="token keyword">VARCHAR</span><span class="token punctuation">(</span><span class="token number">10</span><span class="token punctuation">)</span><span class="token punctuation">,</span>
  student_birthday <span class="token keyword">DATETIME</span><span class="token punctuation">,</span>
  student_phone <span class="token keyword">INT</span><span class="token punctuation">,</span>
  student_score <span class="token keyword">FLOAT</span>
<span class="token punctuation">)</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="_6-2-实体完整性-唯一约束" tabindex="-1"><a class="header-anchor" href="#_6-2-实体完整性-唯一约束" aria-hidden="true">#</a> 6.2. 实体完整性--唯一约束</h3><p>关键字：<code>UNIQUE</code></p><p>唯一约束是指给定列的值必须唯一，与主键约束不同的是它可以为空。通常加在表中不能重复的信息中，如电话号码。</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">CREATE</span> <span class="token keyword">TABLE</span> t_student<span class="token punctuation">(</span>
  student_id <span class="token keyword">INT</span> <span class="token keyword">PRIMARY</span> <span class="token keyword">KEY</span><span class="token punctuation">,</span>
  student_name <span class="token keyword">VARCHAR</span><span class="token punctuation">(</span><span class="token number">10</span><span class="token punctuation">)</span><span class="token punctuation">,</span>
  student_birthday <span class="token keyword">DATETIME</span><span class="token punctuation">,</span>
  student_phone <span class="token keyword">INT</span> <span class="token keyword">UNIQUE</span><span class="token punctuation">,</span>
  student_score <span class="token keyword">FLOAT</span>
<span class="token punctuation">)</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="_6-3-域完整性-非空约束" tabindex="-1"><a class="header-anchor" href="#_6-3-域完整性-非空约束" aria-hidden="true">#</a> 6.3. 域完整性--非空约束</h3><p>关键字：<code>NOT NULL</code></p><p>非空约束可以加在诸如姓名等列上。</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">CREATE</span> <span class="token keyword">TABLE</span> t_student<span class="token punctuation">(</span>
  student_id <span class="token keyword">INT</span> <span class="token keyword">PRIMARY</span> <span class="token keyword">KEY</span><span class="token punctuation">,</span>
  student_name <span class="token keyword">VARCHAR</span><span class="token punctuation">(</span><span class="token number">10</span><span class="token punctuation">)</span> <span class="token operator">NOT</span> <span class="token boolean">NULL</span><span class="token punctuation">,</span>
  student_birthday <span class="token keyword">DATETIME</span><span class="token punctuation">,</span>
  student_phone <span class="token keyword">INT</span> <span class="token keyword">UNIQUE</span><span class="token punctuation">,</span>
  student_score <span class="token keyword">FLOAT</span>
<span class="token punctuation">)</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="_6-4-域完整性-默认约束" tabindex="-1"><a class="header-anchor" href="#_6-4-域完整性-默认约束" aria-hidden="true">#</a> 6.4. 域完整性--默认约束</h3><p>关键字：<code>DEFAULT</code></p><p>设定默认值后，可以在添加此列时不指定值,数据库会自动填充设定的默认值。</p><p>现给学生表加入性别列，默认值设为“男”，这样添加新的学生信息时如果没有填写具体的性别均会默认为男性：</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">CREATE</span> <span class="token keyword">TABLE</span> t_student<span class="token punctuation">(</span>
  student_id <span class="token keyword">INT</span> <span class="token keyword">PRIMARY</span> <span class="token keyword">KEY</span><span class="token punctuation">,</span>
  student_name <span class="token keyword">VARCHAR</span><span class="token punctuation">(</span><span class="token number">10</span><span class="token punctuation">)</span> <span class="token operator">NOT</span> <span class="token boolean">NULL</span><span class="token punctuation">,</span>
  student_sex <span class="token keyword">VARCHAR</span><span class="token punctuation">(</span><span class="token number">5</span><span class="token punctuation">)</span> <span class="token keyword">DEFAULT</span> <span class="token string">&#39;男&#39;</span><span class="token punctuation">,</span>
  student_birthday <span class="token keyword">DATETIME</span><span class="token punctuation">,</span>
  student_phone <span class="token keyword">INT</span> <span class="token keyword">UNIQUE</span><span class="token punctuation">,</span>
  student_score <span class="token keyword">FLOAT</span>
<span class="token punctuation">)</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><img src="https://pic.downk.cc/item/5e858713504f4bcb04cf85ed.jpg" alt="" loading="lazy"></p><h3 id="_6-5-引用完整性-外键约束" tabindex="-1"><a class="header-anchor" href="#_6-5-引用完整性-外键约束" aria-hidden="true">#</a> 6.5. 引用完整性--外键约束</h3><p>外键约束是指在外键关联主键上强制加上一个约束，如果违反该约束，则不允许该条数据的修改。可以通过两种方式创建，第一种是在创建表的同时创建约束，第二种是已经创建表后，再来创建约束。</p><h4 id="_6-5-1-1-创建表时-同时创建约束" tabindex="-1"><a class="header-anchor" href="#_6-5-1-1-创建表时-同时创建约束" aria-hidden="true">#</a> 6.5.1. 1.创建表时，同时创建约束</h4><p>创建主表--班级表：</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">CREATE</span> <span class="token keyword">TABLE</span> t_class<span class="token punctuation">(</span>
  class_id <span class="token keyword">INT</span> <span class="token keyword">PRIMARY</span> <span class="token keyword">KEY</span><span class="token punctuation">,</span>
  class_name <span class="token keyword">VARCHAR</span><span class="token punctuation">(</span><span class="token number">20</span><span class="token punctuation">)</span> <span class="token keyword">UNIQUE</span> <span class="token operator">NOT</span> <span class="token boolean">NULL</span>
<span class="token punctuation">)</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>创建从表--学生表，并设置外键约束：</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">CREATE</span> <span class="token keyword">TABLE</span> t_student<span class="token punctuation">(</span>
  student_id <span class="token keyword">INT</span> <span class="token keyword">PRIMARY</span> <span class="token keyword">KEY</span><span class="token punctuation">,</span>
  s_c_id <span class="token keyword">INT</span><span class="token punctuation">,</span>
  student_name <span class="token keyword">VARCHAR</span><span class="token punctuation">(</span><span class="token number">10</span><span class="token punctuation">)</span> <span class="token operator">NOT</span> <span class="token boolean">NULL</span><span class="token punctuation">,</span>
  student_sex <span class="token keyword">VARCHAR</span><span class="token punctuation">(</span><span class="token number">5</span><span class="token punctuation">)</span> <span class="token keyword">DEFAULT</span> <span class="token string">&#39;男&#39;</span><span class="token punctuation">,</span>
  student_birthday <span class="token keyword">DATETIME</span><span class="token punctuation">,</span>
  student_phone <span class="token keyword">INT</span> <span class="token keyword">UNIQUE</span><span class="token punctuation">,</span>
  student_score <span class="token keyword">FLOAT</span><span class="token punctuation">,</span>
  <span class="token keyword">CONSTRAINT</span> fk_class_id <span class="token keyword">FOREIGN</span> <span class="token keyword">KEY</span><span class="token punctuation">(</span>s_c_id<span class="token punctuation">)</span> <span class="token keyword">REFERENCES</span> t_class<span class="token punctuation">(</span>class_id<span class="token punctuation">)</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>上面的第8行代码就是创建外键约束的方法，个人认为也是<code>SQL</code>语句中最难记的。</p><div class="hint-container info"><p class="hint-container-title">提示</p><p>创建约束后，那么在创建学生时，必须关联到对应的班级，不能独立创建没有班级的学生。</p></div><h4 id="_6-5-2-2-已创建表后-追加外键约束" tabindex="-1"><a class="header-anchor" href="#_6-5-2-2-已创建表后-追加外键约束" aria-hidden="true">#</a> 6.5.2. 2.已创建表后，追加外键约束</h4><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">ALTER</span> <span class="token keyword">table</span> t_student
<span class="token keyword">ADD</span>
  <span class="token keyword">CONSTRAINT</span> fk_class_id <span class="token keyword">FOREIGN</span> <span class="token keyword">KEY</span><span class="token punctuation">(</span>s_c_id<span class="token punctuation">)</span> <span class="token keyword">REFERENCES</span> t_class<span class="token punctuation">(</span>class_id<span class="token punctuation">)</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>这里值得注意的是，在追加约束时，如果我们已创建好的表中有不符合约束条件的数据，那么将会报错约束冲突，可以通过添加语句<code>WITH NOCHECK</code>解决，这样就只会对后面新加的数据进行校验，而前面已有的数据忽略不管。</p><p>上述语句可修改为如下：</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">ALTER</span> <span class="token keyword">table</span> t_student <span class="token keyword">WITH</span> NOCHECK
<span class="token keyword">ADD</span>
  <span class="token keyword">CONSTRAINT</span> fk_class_id <span class="token keyword">FOREIGN</span> <span class="token keyword">KEY</span><span class="token punctuation">(</span>s_c_id<span class="token punctuation">)</span> <span class="token keyword">REFERENCES</span> t_class<span class="token punctuation">(</span>class_id<span class="token punctuation">)</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>由于外键约束会降低数据库的性能，大部分互联网应用程序为了追求速度，并不设置外键约束，而是仅靠应用程序自身来保证逻辑的正确性。这种情况下，<code>s_c_id</code>仅仅是一个普通的列，只是它起到了外键的作用而已。</p><h4 id="_6-5-3-3-删除外键约束" tabindex="-1"><a class="header-anchor" href="#_6-5-3-3-删除外键约束" aria-hidden="true">#</a> 6.5.3. 3.删除外键约束</h4><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">ALTER</span> <span class="token keyword">TABLE</span> t_student <span class="token keyword">drop</span> <span class="token keyword">FOREIGN</span> <span class="token keyword">KEY</span> fk_class_id<span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><div class="hint-container warning"><p class="hint-container-title">注意</p><p>删除外键约束并没有删除外键这一列，只是去除外键将这一列（<code>s_c_id</code>）变为一个普通的列。删除列是通过<code>DROP COLUMN ...</code>实现的。</p></div>`,113);function k(h,v){const a=p("font");return c(),l("div",null,[r,n("ul",null,[n("li",null,[n("p",null,[s("第一个字符必须为下列之一："),e(a,{color:"green"},{default:t(()=>[s("字母、下划线、#及@符号。")]),_:1})])]),n("li",null,[n("p",null,[s("后续字符由"),e(a,{color:"green"},{default:t(()=>[s("字母、十进制数、下划线、#、$及@符号")]),_:1}),s("组成。")])]),n("li",null,[n("p",null,[s("不能为"),e(a,{color:"green"},{default:t(()=>[s("RDBMS（关系型数据库管理系统）")]),_:1}),s("的保留关键字。")])]),n("li",null,[n("p",null,[s("不允许"),e(a,{color:"green"},{default:t(()=>[s("空格及其他字符")]),_:1}),s("。")])])]),u])}const m=o(i,[["render",k],["__file","1.html.vue"]]);export{m as default};
